	}

	fu := &models.ReviewFollowUp{
		ID:        uuid.New(),
		RequestID: requestID,
		AuthorID:  authorID,
		Content:   req.Content,
		Level:     request.CurrentLevel,
		CreatedAt: time.Now(),
	}

	if err := s.repo.CreateFollowUp(ctx, fu); err != nil {
		return nil, err
	}

	s.audit.Log(ctx, "review_follow_up", fu.ID, authorID, "added", map[string]interface{}{
		"request_id": requestID,
		"level":      fu.Level,
	})

	return fu, nil
}

