import (
	"context"
	"os"
	"runtime"
	"sync"
	"sync/atomic"
	"time"

	"github.com/jmoiron/sqlx"
)

// Metrics tracks request-level metrics in memory
type Metrics struct {
	mu             sync.RWMutex
	requestCount   int64
	errorCount     int64
	activeSessions int64
	latencies      []time.Duration // ring buffer
	latencyIdx     int
	startTime      time.Time
}

func NewMetrics() *Metrics {
	return &Metrics{
		latencies: make([]time.Duration, 1000), // last 1000 requests
		startTime: time.Now(),
	}
}

func (m *Metrics) RecordRequest(duration time.Duration, isError bool) {
	atomic.AddInt64(&m.requestCount, 1)
	if isError {
		atomic.AddInt64(&m.errorCount, 1)
	}
	m.mu.Lock()
	m.latencies[m.latencyIdx%len(m.latencies)] = duration
	m.latencyIdx++
	m.mu.Unlock()
}

func (m *Metrics) IncrSessions() {
	atomic.AddInt64(&m.activeSessions, 1)
}

func (m *Metrics) DecrSessions() {
	atomic.AddInt64(&m.activeSessions, -1)
}

func (m *Metrics) GetSnapshot() MetricsSnapshot {
	m.mu.RLock()
	defer m.mu.RUnlock()

	count := m.latencyIdx
	if count > len(m.latencies) {
		count = len(m.latencies)
	}

	// Collect non-zero latencies
	var latencies []time.Duration
	for i := 0; i < count; i++ {
		if m.latencies[i] > 0 {
			latencies = append(latencies, m.latencies[i])
		}
	}

	// Sort for percentile calculation
	sortDurations(latencies)

	var p50, p95, p99 time.Duration
	if len(latencies) > 0 {
		p50 = latencies[len(latencies)*50/100]
		p95 = latencies[len(latencies)*95/100]
		p99 = latencies[len(latencies)*99/100]
	}

	return MetricsSnapshot{
		RequestCount:   atomic.LoadInt64(&m.requestCount),
		ErrorCount:     atomic.LoadInt64(&m.errorCount),
		ActiveSessions: atomic.LoadInt64(&m.activeSessions),
		P50Latency:     p50,
		P95Latency:     p95,
		P99Latency:     p99,
		Uptime:         time.Since(m.startTime),
	}
}

type MetricsSnapshot struct {
	RequestCount   int64         `json:"request_count"`
	ErrorCount     int64         `json:"error_count"`
	ActiveSessions int64         `json:"active_sessions"`
	P50Latency     time.Duration `json:"p50_latency_ms"`
	P95Latency     time.Duration `json:"p95_latency_ms"`
	P99Latency     time.Duration `json:"p99_latency_ms"`
	Uptime         time.Duration `json:"uptime_seconds"`
}

func sortDurations(d []time.Duration) {
	for i := 1; i < len(d); i++ {
		for j := i; j > 0 && d[j] < d[j-1]; j-- {
			d[j], d[j-1] = d[j-1], d[j]
