143	func (s *CourseService) CreateOutlineNode(ctx context.Context, req *dto.CreateOutlineNodeRequest, actorID uuid.UUID) (*models.CourseOutlineNode, error) {
144		courseID, err := uuid.Parse(req.CourseID)
145		if err != nil {
146			return nil, fmt.Errorf("invalid course_id")
147		}
148		if _, err := s.courseRepo.GetByID(ctx, courseID); err != nil {
149			return nil, ErrCourseNotFound
150		}
151		if err := s.requireStaff(ctx, courseID, actorID); err != nil {
152			return nil, err
153		}
154	
155		nodeType := models.OutlineNodeType(req.NodeType)
156		if !models.ValidNodeTypes[nodeType] {
157			return nil, ErrInvalidNodeType
158		}
159		if req.Title == "" {
160			return nil, fmt.Errorf("title is required")
161		}
162	
163		var parentID *uuid.UUID
164		if req.ParentID != nil {
165			pid, err := uuid.Parse(*req.ParentID)
166			if err != nil {
167				return nil, fmt.Errorf("invalid parent_id")
168			}
169			parentID = &pid
170			// Verify parent exists and belongs to same course
171			parent, err := s.outlineRepo.GetByID(ctx, pid)
172			if err != nil {
173				return nil, fmt.Errorf("parent node not found")
174			}
175			if parent.CourseID != courseID {
176				return nil, fmt.Errorf("parent node belongs to a different course")
177			}
178		}
179	
180		now := time.Now()
181		node := &models.CourseOutlineNode{
182			ID:          uuid.New(),
183			CourseID:    courseID,
184			ParentID:    parentID,
185			NodeType:    nodeType,
186			Title:       req.Title,
187			Description: req.Description,
188			OrderIndex:  req.OrderIndex,
189			CreatedAt:   now,
190			UpdatedAt:   now,
191		}
192	
193		if err := s.outlineRepo.Create(ctx, node); err != nil {
194			return nil, err
195		}
196	
197		s.audit.Log(ctx, "course_outline_node", node.ID, actorID, "created", map[string]interface{}{
198			"course_id": courseID,
199			"node_type": string(nodeType),
200			"title":     req.Title,
201		})
202	
203		return node, nil
204	}
