64	func (s *ResourceService) CreateResource(ctx context.Context, req *dto.CreateResourceRequest, actorID uuid.UUID) (*models.Resource, []string, error) {
65		courseID, err := uuid.Parse(req.CourseID)
66		if err != nil {
67			return nil, nil, fmt.Errorf("invalid course_id")
68		}
69		if _, err := s.courseRepo.GetByID(ctx, courseID); err != nil {
70			return nil, nil, fmt.Errorf("course not found")
71		}
72		if req.Title == "" {
73			return nil, nil, fmt.Errorf("title is required")
74		}
75	
76		resType := models.ResourceType(req.ResourceType)
77		if !models.ValidResourceTypes[resType] {
78			return nil, nil, fmt.Errorf("invalid resource_type: %s", req.ResourceType)
79		}
80	
81		visibility := models.ResourceVisibility(req.Visibility)
82		if !models.ValidVisibilities[visibility] {
83			return nil, nil, fmt.Errorf("invalid visibility: %s", req.Visibility)
84		}
85	
86		if resType == models.ResourceTypeLink && (req.LinkURL == nil || *req.LinkURL == "") {
87			return nil, nil, fmt.Errorf("link_url is required for Link resources")
88		}
89	
90		// Validate tags
91		if err := validateTags(req.Tags); err != nil {
92			return nil, nil, err
93		}
94	
95		var nodeID *uuid.UUID
96		if req.NodeID != nil {
97			nid, err := uuid.Parse(*req.NodeID)
98			if err != nil {
99				return nil, nil, fmt.Errorf("invalid node_id")
100			}
101			nodeID = &nid
102		}
103	
104		now := time.Now()
105		resource := &models.Resource{
106			ID:           uuid.New(),
107			CourseID:     courseID,
108			NodeID:       nodeID,
109			Title:        req.Title,
110			Description:  req.Description,
111			ResourceType: resType,
112			Visibility:   visibility,
113			LinkURL:      req.LinkURL,
114			CreatedBy:    actorID,
115			CreatedAt:    now,
116			UpdatedAt:    now,
117		}
118	
119		if err := s.resourceRepo.Create(ctx, resource); err != nil {
120			return nil, nil, err
121		}
122	
123		// Create tags
124		tags := s.saveTags(ctx, resource.ID, req.Tags)
125	
126		s.audit.Log(ctx, "resource", resource.ID, actorID, "created", map[string]interface{}{
127			"course_id":     courseID,
128			"title":         req.Title,
129			"resource_type": string(resType),
130			"visibility":    string(visibility),
131		})
132	
133		return resource, tags, nil
134	}
