176	func (s *ResourceService) UpdateResource(ctx context.Context, id uuid.UUID, req *dto.UpdateResourceRequest, actorID uuid.UUID) (*models.Resource, []string, error) {
177		resource, err := s.resourceRepo.GetByID(ctx, id)
178		if err != nil {
179			return nil, nil, ErrResourceNotFound
180		}
181	
182		if req.Title != nil {
183			resource.Title = *req.Title
184		}
185		if req.Description != nil {
186			resource.Description = req.Description
187		}
188		if req.Visibility != nil {
189			vis := models.ResourceVisibility(*req.Visibility)
190			if !models.ValidVisibilities[vis] {
191				return nil, nil, fmt.Errorf("invalid visibility: %s", *req.Visibility)
192			}
193			resource.Visibility = vis
194		}
195		if req.NodeID != nil {
196			if *req.NodeID == "" {
197				resource.NodeID = nil
198			} else {
199				nid, err := uuid.Parse(*req.NodeID)
200				if err != nil {
201					return nil, nil, fmt.Errorf("invalid node_id")
202				}
203				resource.NodeID = &nid
204			}
205		}
206		if req.LinkURL != nil {
207			resource.LinkURL = req.LinkURL
208		}
209	
210		if err := s.resourceRepo.Update(ctx, resource); err != nil {
211			return nil, nil, err
212		}
213	
214		// Update tags if provided
215		var tags []string
216		if req.Tags != nil {
217			if err := validateTags(req.Tags); err != nil {
218				return nil, nil, err
219			}
220			tags = s.replaceTags(ctx, resource.ID, req.Tags)
221		} else {
222			tags, _ = s.getTagStrings(ctx, id)
223		}
224	
225		s.audit.Log(ctx, "resource", resource.ID, actorID, "updated", map[string]interface{}{
226			"title":      resource.Title,
227			"visibility": string(resource.Visibility),
228		})
