246	// Version management
247	
248	func (s *ResourceService) UploadVersion(ctx context.Context, resourceID uuid.UUID, fileName, mimeType string, sizeBytes int64, fileContent io.Reader, extractedText *string, actorID uuid.UUID) (*models.ResourceVersion, error) {
249		resource, err := s.resourceRepo.GetByID(ctx, resourceID)
250		if err != nil {
251			return nil, ErrResourceNotFound
252		}
253	
254		// Validate mime type
255		if !models.AllowedMimeTypes[mimeType] {
256			return nil, fmt.Errorf("%w: %s", ErrMimeTypeNotAllowed, mimeType)
257		}
258	
259		// Compute SHA-256 while writing to disk
260		storageDir := filepath.Join(s.cfg.StoragePath, resource.CourseID.String(), resourceID.String())
261		if err := os.MkdirAll(storageDir, 0750); err != nil {
262			return nil, fmt.Errorf("creating storage directory: %w", err)
263		}
264	
265		versionID := uuid.New()
266		storagePath := filepath.Join(storageDir, versionID.String())
267	
268		f, err := os.Create(storagePath)
269		if err != nil {
270			return nil, fmt.Errorf("creating file: %w", err)
271		}
272	
273		hasher := sha256.New()
274		written, err := io.Copy(f, io.TeeReader(fileContent, hasher))
275		f.Close()
276		if err != nil {
277			os.Remove(storagePath)
278			return nil, fmt.Errorf("writing file: %w", err)
279		}
280	
281		sha256Hash := hex.EncodeToString(hasher.Sum(nil))
282	
283		// Check for deduplication — if same hash exists, reuse storage path
284		existing, err := s.versionRepo.GetBySHA256(ctx, sha256Hash)
285		if err == nil && existing != nil {
286			// Same file already exists — remove the new copy and reference existing path
287			os.Remove(storagePath)
288			storagePath = existing.StoragePath
289		}
290	
291		// Get next version number
292		latestNum, err := s.versionRepo.GetLatestVersionNumber(ctx, resourceID)
293		if err != nil {
294			return nil, fmt.Errorf("getting latest version: %w", err)
295		}
296	
297		version := &models.ResourceVersion{
298			ID:            versionID,
299			ResourceID:    resourceID,
300			VersionNumber: latestNum + 1,
301			FileName:      fileName,
302			MimeType:      mimeType,
303			SizeBytes:     written,
304			SHA256Hash:    sha256Hash,
305			StoragePath:   storagePath,
306			ExtractedText: extractedText,
307			UploadedBy:    actorID,
308			CreatedAt:     time.Now(),
309		}
310	
311		if err := s.versionRepo.Create(ctx, version); err != nil {
312			return nil, err
313		}
314	
315		// Update latest version pointer
316		if err := s.resourceRepo.UpdateLatestVersion(ctx, resourceID, versionID); err != nil {
317			return nil, err
318		}
319	
320		s.audit.Log(ctx, "resource_version", versionID, actorID, "uploaded", map[string]interface{}{
321			"resource_id":    resourceID,
322			"version_number": version.VersionNumber,
323			"file_name":      fileName,
324			"mime_type":      mimeType,
325			"size_bytes":     written,
326			"sha256_hash":    sha256Hash,
327		})
328	
329		return version, nil
330	}
