150	func (s *ResourceService) ListResources(ctx context.Context, courseID, callerID uuid.UUID, callerRole models.Role, offset, limit int) ([]models.Resource, error) {
151		if limit <= 0 {
152			limit = 20
153		}
154		if limit > 100 {
155			limit = 100
