176	func (s *ResourceService) UpdateResource(ctx context.Context, id uuid.UUID, req *dto.UpdateResourceRequest, actorID uuid.UUID, callerRole models.Role) (*models.Resource, []string, error) {
177		resource, err := s.resourceRepo.GetByID(ctx, id)
178		if err != nil {
179			return nil, nil, ErrResourceNotFound
180		}
181	
182		// Require course staff or admin
183		if err := s.requireCourseStaff(ctx, resource.CourseID, actorID, callerRole); err != nil {
184			return nil, nil, err
185		}
186	
187		if req.Title != nil {
188			resource.Title = *req.Title
189		}
190		if req.Description != nil {
191			resource.Description = req.Description
192		}
193		if req.Visibility != nil {
194			vis := models.ResourceVisibility(*req.Visibility)
195			if !models.ValidVisibilities[vis] {
196				return nil, nil, fmt.Errorf("invalid visibility: %s", *req.Visibility)
197			}
198			resource.Visibility = vis
199		}
200		if req.NodeID != nil {
201			if *req.NodeID == "" {
202				resource.NodeID = nil
203			} else {
204				nid, err := uuid.Parse(*req.NodeID)
205				if err != nil {
206					return nil, nil, fmt.Errorf("invalid node_id")
207				}
208				resource.NodeID = &nid
209			}
210		}
211		if req.LinkURL != nil {
212			resource.LinkURL = req.LinkURL
213		}
214	
215		if err := s.resourceRepo.Update(ctx, resource); err != nil {
216			return nil, nil, err
217		}
218	
219		// Update tags if provided
220		var tags []string
221		if req.Tags != nil {
222			if err := validateTags(req.Tags); err != nil {
223				return nil, nil, err
224			}
225			tags = s.replaceTags(ctx, resource.ID, req.Tags)
226		} else {
227			tags, _ = s.getTagStrings(ctx, id)
228		}
229	
230		s.audit.Log(ctx, "resource", resource.ID, actorID, "updated", map[string]interface{}{
231			"title":      resource.Title,
232			"visibility": string(resource.Visibility),
233		})
234	
235		return resource, tags, nil
236	}
