257	// Version management
258	
259	func (s *ResourceService) UploadVersion(ctx context.Context, resourceID uuid.UUID, fileName, mimeType string, sizeBytes int64, fileContent io.Reader, extractedText *string, actorID uuid.UUID, callerRole models.Role) (*models.ResourceVersion, error) {
260		resource, err := s.resourceRepo.GetByID(ctx, resourceID)
261		if err != nil {
262			return nil, ErrResourceNotFound
263		}
264	
265		// Require course staff or admin
266		if err := s.requireCourseStaff(ctx, resource.CourseID, actorID, callerRole); err != nil {
267			return nil, err
268		}
269	
270		// Validate mime type
271		if !models.AllowedMimeTypes[mimeType] {
272			return nil, fmt.Errorf("%w: %s", ErrMimeTypeNotAllowed, mimeType)
273		}
274	
275		// Compute SHA-256 while writing to disk
276		storageDir := filepath.Join(s.cfg.StoragePath, resource.CourseID.String(), resourceID.String())
277		if err := os.MkdirAll(storageDir, 0750); err != nil {
278			return nil, fmt.Errorf("creating storage directory: %w", err)
279		}
280	
281		versionID := uuid.New()
282		storagePath := filepath.Join(storageDir, versionID.String())
283	
284		f, err := os.Create(storagePath)
285		if err != nil {
286			return nil, fmt.Errorf("creating file: %w", err)
287		}
288	
289		hasher := sha256.New()
290		written, err := io.Copy(f, io.TeeReader(fileContent, hasher))
291		f.Close()
292		if err != nil {
293			os.Remove(storagePath)
294			return nil, fmt.Errorf("writing file: %w", err)
295		}
296	
297		sha256Hash := hex.EncodeToString(hasher.Sum(nil))
298	
299		// Check for deduplication — if same hash exists, reuse storage path
300		existing, err := s.versionRepo.GetBySHA256(ctx, sha256Hash)
301		if err == nil && existing != nil {
302			// Same file already exists — remove the new copy and reference existing path
303			os.Remove(storagePath)
304			storagePath = existing.StoragePath
305		}
306	
307		// Get next version number
308		latestNum, err := s.versionRepo.GetLatestVersionNumber(ctx, resourceID)
309		if err != nil {
310			return nil, fmt.Errorf("getting latest version: %w", err)
311		}
312	
313		version := &models.ResourceVersion{
314			ID:            versionID,
315			ResourceID:    resourceID,
316			VersionNumber: latestNum + 1,
317			FileName:      fileName,
318			MimeType:      mimeType,
319			SizeBytes:     written,
320			SHA256Hash:    sha256Hash,
321			StoragePath:   storagePath,
322			ExtractedText: extractedText,
323			UploadedBy:    actorID,
324			CreatedAt:     time.Now(),
325		}
326	
327		if err := s.versionRepo.Create(ctx, version); err != nil {
328			return nil, err
329		}
330	
331		// Update latest version pointer
332		if err := s.resourceRepo.UpdateLatestVersion(ctx, resourceID, versionID); err != nil {
333			return nil, err
334		}
335	
336		s.audit.Log(ctx, "resource_version", versionID, actorID, "uploaded", map[string]interface{}{
337			"resource_id":    resourceID,
338			"version_number": version.VersionNumber,
339			"file_name":      fileName,
340			"mime_type":      mimeType,
341			"size_bytes":     written,
342			"sha256_hash":    sha256Hash,
343		})
344	
345		return version, nil
346	}
