387	func (s *ResourceService) checkResourceAccess(ctx context.Context, resource *models.Resource, callerID uuid.UUID, callerRole models.Role) error {
388		if callerRole == models.RoleAdministrator {
389			return nil
390		}
391	
392		m, err := s.memberRepo.GetByAccountAndCourse(ctx, callerID, resource.CourseID)
393		if err != nil {
394			if errors.Is(err, sql.ErrNoRows) {
395				return ErrResourceAccessDenied
396			}
397			return err
398		}
399	
400		// Staff can see everything
401		if m.Role == models.MembershipRoleStaff {
402			return nil
403		}
404	
405		// Enrolled users can only see Enrolled-visibility resources
406		if resource.Visibility == models.VisibilityStaff {
407			return ErrResourceAccessDenied
408		}
409	
410		return nil
411	}
