441	
442	func validateTags(tags []string) error {
443		if len(tags) > maxTagsPerResource {
444			return ErrTooManyTags
445		}
446		for _, t := range tags {
447			if len(t) > maxTagLength {
448				return fmt.Errorf("%w: '%s'", ErrTagTooLong, t)
449			}
450			if t == "" {
451				return fmt.Errorf("tags cannot be empty strings")
452			}
453		}
454		return nil
455	}
