457	func (s *ResourceService) saveTags(ctx context.Context, resourceID uuid.UUID, tagStrings []string) []string {
458		now := time.Now()
459		for _, t := range tagStrings {
460			tag := &models.ResourceTag{
461				ID:         uuid.New(),
462				ResourceID: resourceID,
463				Tag:        t,
464				CreatedAt:  now,
465			}
466			s.tagRepo.Create(ctx, tag)
467		}
468		return tagStrings
469	}
