471	func (s *ResourceService) replaceTags(ctx context.Context, resourceID uuid.UUID, tagStrings []string) []string {
472		now := time.Now()
473		tags := make([]models.ResourceTag, len(tagStrings))
474		for i, t := range tagStrings {
475			tags[i] = models.ResourceTag{
476				ID:         uuid.New(),
477				ResourceID: resourceID,
478				Tag:        t,
479				CreatedAt:  now,
480			}
481		}
482		s.tagRepo.ReplaceAll(ctx, resourceID, tags)
483		return tagStrings
484	}
