486	func (s *ResourceService) getTagStrings(ctx context.Context, resourceID uuid.UUID) ([]string, error) {
487		tags, err := s.tagRepo.ListByResource(ctx, resourceID)
488		if err != nil {
489			return nil, err
490		}
491		result := make([]string, len(tags))
492		for i, t := range tags {
493			result[i] = t.Tag
494		}
495		return result, nil
496	}
