97	func (h *AccountHandler) ChangePassword(c echo.Context) error {
98		id, err := uuid.Parse(c.Param("id"))
99		if err != nil {
100			return echo.NewHTTPError(http.StatusBadRequest, "invalid account id")
101		}
102	
103		// Only the account owner can change their own password
104		callerID, _ := c.Get("account_id").(uuid.UUID)
105		if callerID != id {
106			return echo.NewHTTPError(http.StatusForbidden, "you can only change your own password")
107		}
108	
109		var req dto.ChangePasswordRequest
110		if err := c.Bind(&req); err != nil {
111			return echo.NewHTTPError(http.StatusBadRequest, "invalid request body")
112		}
113		if req.OldPassword == "" || req.NewPassword == "" {
114			return echo.NewHTTPError(http.StatusBadRequest, "old_password and new_password are required")
115		}
116	
117		if err := h.accountService.ChangePassword(c.Request().Context(), id, req.OldPassword, req.NewPassword); err != nil {
118			if errors.Is(err, service.ErrInvalidCredentials) {
119				return echo.NewHTTPError(http.StatusUnauthorized, "incorrect current password")
120			}
121			if errors.Is(err, service.ErrPasswordPolicy) {
122				return echo.NewHTTPError(http.StatusBadRequest, err.Error())
123			}
124			return echo.NewHTTPError(http.StatusInternalServerError, "internal server error")
125		}
126	
127		return c.JSON(http.StatusOK, map[string]string{"message": "password changed successfully"})
128	}
