100		if err != nil {
101			return fmt.Errorf("account_service.ChangePassword: %w", err)
102		}
103	
104		if err := bcrypt.CompareHashAndPassword([]byte(account.PasswordHash), []byte(oldPassword)); err != nil {
105			return ErrInvalidCredentials
106		}
107	
108		if err := ValidatePassword(newPassword); err != nil {
109			return err
110		}
111	
112		hash, err := bcrypt.GenerateFromPassword([]byte(newPassword), s.cfg.BcryptCost)
113		if err != nil {
114			return fmt.Errorf("account_service.ChangePassword: %w", err)
115		}
116	
117		if err := s.accountRepo.UpdatePassword(ctx, accountID, string(hash)); err != nil {
118			return err
119		}
120	
121		// Revoke all refresh tokens to force re-login on all devices
122		return s.refreshTokenRepo.RevokeAllForAccount(ctx, accountID)
123	}
