56	func (s *AuthService) Login(ctx context.Context, req *dto.LoginRequest, ipAddress string) (*dto.LoginResponse, error) {
57		account, err := s.accountRepo.GetByUsername(ctx, req.Username)
58		if err != nil {
59			// Prevent timing-based user enumeration: always hash
60			bcrypt.CompareHashAndPassword([]byte("$2a$12$000000000000000000000000000000000000000000000000000000"), []byte(req.Password))
61			return nil, ErrInvalidCredentials
62		}
63	
64		if account.Status != models.StatusActive {
65			return nil, ErrAccountNotActive
66		}
67	
68		// Check lockout
69		failCount, err := s.loginAttemptRepo.CountRecentFailures(ctx, account.ID, s.cfg.LockoutDuration)
70		if err != nil {
71			return nil, fmt.Errorf("auth_service.Login: %w", err)
72		}
73		if failCount >= s.cfg.MaxLoginAttempts {
74			return nil, ErrAccountLocked
75		}
76	
77		// Verify password
78		if err := bcrypt.CompareHashAndPassword([]byte(account.PasswordHash), []byte(req.Password)); err != nil {
79			// Record failed attempt
80			s.recordAttempt(ctx, account.ID, false, ipAddress)
81			return nil, ErrInvalidCredentials
82		}
83	
84		// Record successful attempt
85		s.recordAttempt(ctx, account.ID, true, ipAddress)
86	
87		// Handle device fingerprint
88		var deviceID *uuid.UUID
89		if req.DeviceFingerprint != nil {
90			fpHash := s.deviceService.ComputeFingerprint(req.DeviceFingerprint.UserAgent, req.DeviceFingerprint.Attributes)
91			device, err := s.deviceService.RegisterOrUpdateDevice(ctx, account.ID, fpHash, nil)
92			if err == nil {
93				deviceID = &device.ID
94			}
95		}
96	
97		// Generate tokens
98		accessToken, err := s.tokenService.GenerateAccessToken(account)
99		if err != nil {
100			return nil, fmt.Errorf("auth_service.Login: %w", err)
101		}
102	
103		rawRefresh, hashedRefresh, err := s.tokenService.GenerateRefreshToken()
104		if err != nil {
105			return nil, fmt.Errorf("auth_service.Login: %w", err)
106		}
107	
108		now := time.Now()
109		refreshToken := &models.RefreshToken{
110			ID:        uuid.New(),
111			AccountID: account.ID,
112			TokenHash: hashedRefresh,
113			DeviceID:  deviceID,
114			ExpiresAt: now.Add(s.cfg.RefreshTokenTTL),
115			Revoked:   false,
116			CreatedAt: now,
117		}
118		if err := s.refreshTokenRepo.Create(ctx, refreshToken); err != nil {
119			return nil, fmt.Errorf("auth_service.Login: %w", err)
120		}
121	
122		return &dto.LoginResponse{
123			AccessToken:  accessToken,
124			RefreshToken: rawRefresh,
125			ExpiresIn:    int(s.cfg.AccessTokenTTL.Seconds()),
126			Account:      dto.ToAccountResponse(account),
127		}, nil
128	}
129	
130	func (s *AuthService) Refresh(ctx context.Context, rawRefreshToken string) (*dto.RefreshResponse, error) {
131		hashed := HashRefreshToken(rawRefreshToken)
132		stored, err := s.refreshTokenRepo.GetByHash(ctx, hashed)
133		if err != nil {
134			return nil, ErrTokenInvalid
135		}
136	
137		// Reuse detection: if token was already revoked, revoke all tokens for the account
138		if stored.Revoked {
139			s.refreshTokenRepo.RevokeAllForAccount(ctx, stored.AccountID)
140			return nil, ErrTokenReuse
141		}
142	
143		if time.Now().After(stored.ExpiresAt) {
144			return nil, ErrTokenInvalid
145		}
146	
147		// Revoke the current token
148		if err := s.refreshTokenRepo.Revoke(ctx, stored.ID); err != nil {
149			return nil, fmt.Errorf("auth_service.Refresh: %w", err)
150		}
151	
152		// Get account for new access token
153		account, err := s.accountRepo.GetByID(ctx, stored.AccountID)
154		if err != nil {
155			return nil, fmt.Errorf("auth_service.Refresh: %w", err)
156		}
157	
158		if account.Status != models.StatusActive {
159			return nil, ErrAccountNotActive
160		}
161	
162		// Generate new token pair
163		accessToken, err := s.tokenService.GenerateAccessToken(account)
164		if err != nil {
165			return nil, fmt.Errorf("auth_service.Refresh: %w", err)
166		}
167	
168		newRaw, newHashed, err := s.tokenService.GenerateRefreshToken()
169		if err != nil {
170			return nil, fmt.Errorf("auth_service.Refresh: %w", err)
171		}
172	
173		now := time.Now()
174		newRefreshToken := &models.RefreshToken{
175			ID:        uuid.New(),
176			AccountID: stored.AccountID,
177			TokenHash: newHashed,
178			DeviceID:  stored.DeviceID,
179			ExpiresAt: now.Add(s.cfg.RefreshTokenTTL),
180			Revoked:   false,
181			CreatedAt: now,
182		}
183		if err := s.refreshTokenRepo.Create(ctx, newRefreshToken); err != nil {
184			return nil, fmt.Errorf("auth_service.Refresh: %w", err)
185		}
186	
187		return &dto.RefreshResponse{
188			AccessToken:  accessToken,
189			RefreshToken: newRaw,
190			ExpiresIn:    int(s.cfg.AccessTokenTTL.Seconds()),
191		}, nil
192	}
193	
194	func (s *AuthService) Logout(ctx context.Context, rawRefreshToken string) error {
195		hashed := HashRefreshToken(rawRefreshToken)
196		stored, err := s.refreshTokenRepo.GetByHash(ctx, hashed)
197		if err != nil {
198			if errors.Is(err, sql.ErrNoRows) {
199				return nil // Already logged out or invalid, no-op
200			}
201			return fmt.Errorf("auth_service.Logout: %w", err)
202		}
203		return s.refreshTokenRepo.Revoke(ctx, stored.ID)
204	}
