206	func ValidatePassword(password string) error {
207		var errs []string
208	
209		if len(password) < 12 {
210			errs = append(errs, "at least 12 characters")
211		}
212	
213		var hasUpper, hasLower, hasDigit bool
214		for _, ch := range password {
215			switch {
216			case unicode.IsUpper(ch):
217				hasUpper = true
218			case unicode.IsLower(ch):
219				hasLower = true
220			case unicode.IsDigit(ch):
221				hasDigit = true
222			}
223		}
224	
225		if !hasUpper {
226			errs = append(errs, "at least 1 uppercase letter")
227		}
228		if !hasLower {
229			errs = append(errs, "at least 1 lowercase letter")
230		}
231		if !hasDigit {
232			errs = append(errs, "at least 1 number")
233		}
234	
235		if len(errs) > 0 {
236			return fmt.Errorf("%w: password must contain %s", ErrPasswordPolicy, strings.Join(errs, ", "))
237		}
238		return nil
239	}
